-- ─────────────────────────────────────────────────────────────────────────────
-- Seed ref_airports from legacy venturo-erp（漫途用過的 6,075 機場）
-- 來源：舊 venturo-erp Supabase（ref=wzvwmawpkapcmkfmkvav）/ public.ref_airports
-- 欄位對齊：舊 english_name → 新 name_en（cctk B1 commit a4baa57 已修 schema）
-- 砍欄位：workspace_id（ref 表是共用、cctk B2 已砍 trigger_auto_set_workspace_id）
-- 不灌：created_at / is_favorite / usage_count（用預設值）
-- ─────────────────────────────────────────────────────────────────────────────

BEGIN;

ON CONFLICT (iata_code) DO UPDATE SET
  icao_code = EXCLUDED.icao_code,
  name_en = EXCLUDED.name_en,
  name_zh = EXCLUDED.name_zh,
  city_code = EXCLUDED.city_code,
  city_name_en = EXCLUDED.city_name_en,
  city_name_zh = EXCLUDED.city_name_zh,
  country_code = EXCLUDED.country_code,
  timezone = EXCLUDED.timezone,
  latitude = EXCLUDED.latitude,
  longitude = EXCLUDED.longitude;

NOTIFY pgrst, 'reload schema';

COMMIT;
